export const body = "\n\n<header class=\"ss-bar\">\n  <div class=\"ss-bar__inner\">\n    <div class=\"ss-bar__brand\">\n      <a class=\"ss-bar__logo\" href=\"/\"><img src=\"/logo-full.jpg\" alt=\"EuroMedPartner\"></a>\n      <span class=\"ss-bar__divider\"></span>\n      <span class=\"ss-bar__band\">\n        <span class=\"ss-bar__band-tag\">Bando attivo</span>\n        <span class=\"ss-bar__band-name\">Smart<span class=\"accent\">&amp;</span>Start <span class=\"accent\">Italia</span></span>\n      </span>\n    </div>\n    <nav class=\"ss-bar__steps\" aria-label=\"Progresso funnel\"><a class=\"ss-step ss-step--done\" href=\"/\"><span class=\"ss-step__num\">01</span><span class=\"ss-step__label\">Diagnosi</span></a><a class=\"ss-step ss-step--done\" href=\"/quiz\"><span class=\"ss-step__num\">02</span><span class=\"ss-step__label\">Quiz</span></a><a class=\"ss-step ss-step--current\" href=\"/optin\"><span class=\"ss-step__num\">03</span><span class=\"ss-step__label\">Profilo</span></a><a class=\"ss-step\" href=\"/booking\"><span class=\"ss-step__num\">04</span><span class=\"ss-step__label\">Call</span></a></nav>\n    <div></div>\n  </div>\n  <div class=\"ss-bar__progress\"><div class=\"ss-bar__progress-track\"></div><div class=\"ss-bar__progress-fill\" style=\"width:67%\"></div></div>\n</header>\n\n<section class=\"optin\">\n\n  <!-- LEFT: Form -->\n  <div class=\"opt-form-wrap\">\n    <div class=\"opt-sum__tag\" id=\"qualBadge\">\n      <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M20 6 9 17l-5-5\"/></svg>\n      <span>Profilo idoneo</span>\n    </div>\n    <h1 class=\"opt-title\" id=\"optTitle\">Sblocca il <em>report completo</em> del tuo progetto.</h1>\n    <p class=\"opt-lede\" id=\"optLede\">Pochi dati e ricevi via email i bandi compatibili, la stima dettagliata Smart&amp;Start e una call gratuita con un EU Project Manager dedicato al tuo profilo.</p>\n\n    <form class=\"opt-form\" id=\"optForm\">\n      <div class=\"opt-form__row\">\n        <label>Nome\n          <input required name=\"firstName\" placeholder=\"Maria\" autocomplete=\"given-name\">\n        </label>\n        <label>Cognome\n          <input required name=\"lastName\" placeholder=\"Rossi\" autocomplete=\"family-name\">\n        </label>\n      </div>\n      <label>Email aziendale\n        <input required type=\"email\" name=\"email\" placeholder=\"maria.rossi@impresa.it\" autocomplete=\"email\">\n      </label>\n      <label>Telefono\n        <input required type=\"tel\" name=\"phone\" placeholder=\"+39 333 1234567\" autocomplete=\"tel\">\n      </label>\n      <label>Nome dell'azienda\n        <input required name=\"company\" placeholder=\"Impresa S.r.l.\" autocomplete=\"organization\">\n      </label>\n      <label>Ruolo aziendale\n        <input name=\"role\" placeholder=\"CEO, CFO, Innovation Manager…\" autocomplete=\"organization-title\">\n      </label>\n\n      <label class=\"opt-form__check\" style=\"margin-top:8px\">\n        <input type=\"checkbox\" required>\n        <span>Ho letto e accetto la <a href=\"#\">Privacy Policy</a> e autorizzo il trattamento dei dati ai sensi del GDPR.</span>\n      </label>\n      <button type=\"submit\" class=\"btn btn--primary opt-form__submit\">\n        Vedi i bandi compatibili\n        <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><path d=\"M5 12h14M13 5l7 7-7 7\"/></svg>\n      </button>\n      <p class=\"opt-form__legal\">Riceverai il report entro pochi minuti. Non condivideremo mai i tuoi dati con terzi.</p>\n    </form>\n  </div>\n\n  <!-- RIGHT: Dark summary -->\n  <aside class=\"opt-summary\">\n    <div class=\"opt-sum__inner\">\n      <div class=\"opt-sum__est\" id=\"ssEst\">\n        <div class=\"opt-sum__est-label\">Stima Smart&Start Italia · in base alle tue risposte</div>\n        <div class=\"opt-sum__est-amount\" id=\"ssEstAmount\">fino a € —</div>\n        <div class=\"opt-sum__est-range\" id=\"ssEstRange\">range stimato: — — —</div>\n        <div class=\"opt-sum__est-breakdown\">\n          <div class=\"opt-sum__est-row\">\n            <span class=\"opt-sum__est-row-key\">Finanziamento agevolato 0%</span>\n            <span class=\"opt-sum__est-row-val\" id=\"ssEstLoan\">— <span class=\"unit\">EUR</span></span>\n          </div>\n          <div class=\"opt-sum__est-row\">\n            <span class=\"opt-sum__est-row-key\">Fondo perduto</span>\n            <span class=\"opt-sum__est-row-val\" id=\"ssEstGrant\">— <span class=\"unit\">EUR</span></span>\n          </div>\n        </div>\n        <p class=\"opt-sum__est-note\" id=\"ssEstNote\">Stima indicativa basata sui parametri Smart&Start Italia (max €1,5M, 80% del progetto a tasso 0, +35% in fondo perduto al Mezzogiorno).</p>\n      </div>\n\n      <div class=\"opt-sum__answers\" id=\"answersBlock\">\n        <!-- populated by JS -->\n      </div>\n\n      <div class=\"opt-sum__matches\">\n        <div class=\"opt-sum__matches-label\">Bandi compatibili</div>\n        <div class=\"opt-sum__matches-num\" id=\"matchesNum\">12<em>+</em></div>\n        <p class=\"opt-sum__matches-desc\">opportunità di finanziamento attive in linea con il profilo del tuo progetto, per un valore complessivo stimato superiore al milione di euro.</p>\n      </div>\n\n      <div class=\"opt-sum__social\">\n        <div class=\"opt-sum__social-label\">Social proof</div>\n        <div class=\"opt-sum__stats\">\n          <div class=\"opt-sum__stat\"><strong>800+</strong><span>imprese assistite</span></div>\n          <div class=\"opt-sum__stat\"><strong>€42M</strong><span>fondi attivati</span></div>\n          <div class=\"opt-sum__stat\"><strong>98%</strong><span>tasso di successo</span></div>\n        </div>\n        <p class=\"opt-sum__quote\">\"Hanno saputo trasformare un'idea in un progetto finanziato. Trasparenza e professionalità.\"</p>\n        <p class=\"opt-sum__quote-attr\">Giuseppe T. · CEO PMI manifatturiera</p>\n      </div>\n    </div>\n  </aside>\n</section>\n\n<script>\nconst a = JSON.parse(localStorage.getItem('emp_funnel') || '{}');\nif (!a.profilo){\n  // didn't complete the quiz — go back\n  // window.location.href = '/';\n}\n\n// Build answers list\nconst PRETTY = {\n  profilo:    { label:'Profilo' },\n  settore:    { label:'Settore' },\n  dimensione: { label:'Dimensione' },\n  regione:    { label:'Localizzazione' },\n  progetto:   { label:'Tipo progetto' },\n  importo:    { label:'Investimento' },\n  tempistica: { label:'Tempistica' },\n};\n\nconst block = document.getElementById('answersBlock');\nconst rows = [];\nfor (const [key, def] of Object.entries(PRETTY)) {\n  const valLabel = a[key + 'Label'];\n  if (!valLabel) continue;\n  rows.push(`<div class=\"opt-sum__row\"><span class=\"opt-sum__row-key\">${def.label.toLowerCase()}</span><span class=\"opt-sum__row-val\">${valLabel}</span></div>`);\n}\nblock.innerHTML = rows.join('') || '<div class=\"opt-sum__row\"><span class=\"opt-sum__row-key\">nessuna risposta</span><span class=\"opt-sum__row-val\">—</span></div>';\n\n// ====== Smart&Start estimate ======\nconst IMPORTO_MID = { 'lt100': 0, '100-500': 300000, '500-1M': 750000, '1M-1.5M': 1250000 };\nconst IMPORTO_MAX = { 'lt100': 0, '100-500': 500000, '500-1M': 1000000, '1M-1.5M': 1500000 };\nconst IMPORTO_MIN = { 'lt100': 0, '100-500': 100000, '500-1M': 500000, '1M-1.5M': 1000000 };\nconst SUD_REGIONS = ['sud','cratere'];\n\nfunction fmtEur(n){\n  if (!n) return '€ —';\n  if (n >= 1000000) return '€ ' + (n/1000000).toFixed(n%1000000===0?0:2).replace('.',',') + 'M';\n  return '€ ' + Math.round(n/1000) + 'k';\n}\n\nfunction estimate(a){\n  const bucket = a.importo;\n  const project = IMPORTO_MID[bucket] || 0;\n  const minP = IMPORTO_MIN[bucket] || 0;\n  const maxP = IMPORTO_MAX[bucket] || 0;\n  const isSud = SUD_REGIONS.includes(a.regione);\n  const grantRate = isSud ? 0.30 : 0;\n  const loanRate  = 0.80 - grantRate;\n  return { project, loan: Math.round(project*loanRate), grant: Math.round(project*grantRate), total: Math.round(project*0.80), rangeLow: Math.round(minP*0.80), rangeHigh: Math.round(maxP*0.80), isSud, eligible: project > 0 };\n}\n\nconst est = estimate(a);\nif (est.eligible){\n  document.getElementById('ssEstAmount').textContent = 'fino a ' + fmtEur(est.total);\n  document.getElementById('ssEstRange').textContent  = 'range stimato: ' + fmtEur(est.rangeLow) + ' — ' + fmtEur(est.rangeHigh);\n  document.getElementById('ssEstLoan').innerHTML  = fmtEur(est.loan)  + ' <span class=\"unit\">EUR</span>';\n  document.getElementById('ssEstGrant').innerHTML = fmtEur(est.grant) + ' <span class=\"unit\">EUR</span>';\n  document.getElementById('ssEstNote').textContent = est.isSud\n    ? 'Stima Smart&Start Italia: 80% del progetto coperto, di cui 30% a fondo perduto (Sud o cratere sismico). +5% per under 36 o compagine femminile.'\n    : 'Stima Smart&Start Italia: 80% del progetto a tasso 0%, restituzione in 10 anni, nessuna garanzia. Fondo perduto non previsto al Centro-Nord.';\n} else {\n  document.getElementById('ssEstAmount').textContent = 'Investimento sotto soglia';\n  document.getElementById('ssEstRange').textContent  = 'Smart&Start parte da € 100.000 di progetto';\n  document.getElementById('ssEstNote').textContent = 'Per progetti sotto € 100k valutiamo strumenti complementari (voucher, microcredito).';\n}\n\n// ====== Bandi compatibili ======\nfunction diagnose(a){\n  let n = 6;\n  if (['500-1M','1M-1.5M'].includes(a.importo)) n += 4;\n  if (['100-500'].includes(a.importo)) n += 2;\n  if (SUD_REGIONS.includes(a.regione)) n += 3;\n  if (['3m','3-6m'].includes(a.tempistica)) n += 2;\n  if (['mvp','traction','scaling'].includes(a.stadio)) n += 2;\n  if (a.profilo === 'impresa-tradizionale' || a.profilo === 'idea') n -= 3;\n  return Math.max(4, Math.min(n, 24));\n}\nconst matches = diagnose(a);\ndocument.getElementById('matchesNum').innerHTML = matches + '<em>+</em>';\n\nif (a.profilo === 'impresa-tradizionale' || a.profilo === 'idea'){\n  const badge = document.getElementById('qualBadge');\n  badge.classList.add('opt-sum__tag--warn');\n  badge.innerHTML = `<svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"><circle cx=\"12\" cy=\"12\" r=\"10\"/><path d=\"M12 8v4M12 16h.01\"/></svg><span>Profilo da verificare</span>`;\n}\n\n// Form submit — fake — save & advance\ndocument.getElementById('optForm').addEventListener('submit', (e) => {\n  e.preventDefault();\n  const fd = new FormData(e.target);\n  const lead = Object.fromEntries(fd);\n  const all = JSON.parse(localStorage.getItem('emp_funnel') || '{}');\n  Object.assign(all, { lead });\n  localStorage.setItem('emp_funnel', JSON.stringify(all));\n  window.location.href = '/booking';\n});\n</script>\n\n";
